313: // unexpected creates a parser error complaining about an unexpected lexer item.
314: // The item that is presented as unexpected is always the last item produced
315: // by the lexer.
316: func (p *parser) unexpected(context, expected string) {
317: 	var errMsg strings.Builder
318: 
319: 	// Do not report lexer errors twice
320: 	if p.yyParser.lval.item.Typ == ERROR {
321: 		return
322: 	}
323: 
324: 	errMsg.WriteString("unexpected ")
325: 	errMsg.WriteString(p.yyParser.lval.item.desc())
326: 
327: 	if context != "" {
328: 		errMsg.WriteString(" in ")
329: 		errMsg.WriteString(context)
330: 	}
331: 
332: 	if expected != "" {
333: 		errMsg.WriteString(", expected ")
334: 		errMsg.WriteString(expected)
335: 	}
336: 
337: 	p.addParseErr(p.yyParser.lval.item.PositionRange(), errors.New(errMsg.String()))
338: }
